import{_ as s,a as n}from"./chunks/figure-2-failed-breakout.C0mjywzX.js";import{_ as p,o as e,c as i,a1 as l}from"./chunks/framework.BKJzsOC1.js";const m=JSON.parse('{"title":"第一章：科学建仓的基本框架","description":"","frontmatter":{},"headers":[],"relativePath":"trading/intraday-entry/01-scientific-entry-framework.md","filePath":"trading/intraday-entry/01-scientific-entry-framework.md"}'),t={name:"trading/intraday-entry/01-scientific-entry-framework.md"};function c(o,a,d,r,h,u){return e(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="第一章-科学建仓的基本框架" tabindex="-1">第一章：科学建仓的基本框架 <a class="header-anchor" href="#第一章-科学建仓的基本框架" aria-label="Permalink to &quot;第一章：科学建仓的基本框架&quot;">​</a></h1><blockquote><p>建仓不是预测，而是在关键位置等待市场表态；确认后承担有限风险，失效后立即退出。</p></blockquote><h2 id="一、建仓不是预测-而是验证" tabindex="-1">一、建仓不是预测，而是验证 <a class="header-anchor" href="#一、建仓不是预测-而是验证" aria-label="Permalink to &quot;一、建仓不是预测，而是验证&quot;">​</a></h2><p>日内交易不应先预测涨跌，再寻找理由。更稳健的过程是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>提出假设</span></span>
<span class="line"><span>→ 等待价格到达关键位置</span></span>
<span class="line"><span>→ 观察市场反应</span></span>
<span class="line"><span>→ 确认假设成立</span></span>
<span class="line"><span>→ 承担有限风险</span></span></code></pre></div><p>建仓前真正要回答的是：</p><blockquote><p>市场是否已经提供了一个方向清晰、风险可定义、目标明确的机会？</p></blockquote><h2 id="二、建仓的五个要素" tabindex="-1">二、建仓的五个要素 <a class="header-anchor" href="#二、建仓的五个要素" aria-label="Permalink to &quot;二、建仓的五个要素&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>位置 → 触发 → 确认 → 失效 → 目标</span></span></code></pre></div><h3 id="_1-位置" tabindex="-1">1. 位置 <a class="header-anchor" href="#_1-位置" aria-label="Permalink to &quot;1. 位置&quot;">​</a></h3><p>提前标记：</p><ul><li>前高、前低</li><li>开盘区间</li><li>VWAP</li><li>重要整数位</li><li>支撑与阻力</li><li>流动性或成交集中区域</li></ul><p>位置只告诉我们“在哪里观察”，不直接告诉我们“应该买还是卖”。</p><h3 id="_2-触发" tabindex="-1">2. 触发 <a class="header-anchor" href="#_2-触发" aria-label="Permalink to &quot;2. 触发&quot;">​</a></h3><p>常见触发包括：</p><ul><li>突破关键阻力</li><li>跌破关键支撑</li><li>收回此前失守的位置</li><li>触碰边界后形成失败突破</li><li>高低点结构发生改变</li></ul><p>触发代表市场开始表达方向，但不等于立即追单。</p><h3 id="_3-确认" tabindex="-1">3. 确认 <a class="header-anchor" href="#_3-确认" aria-label="Permalink to &quot;3. 确认&quot;">​</a></h3><p>顺势建仓通常需要：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>突破关键位</span></span>
<span class="line"><span>→ 回踩突破位</span></span>
<span class="line"><span>→ 没有重新回到旧区间</span></span>
<span class="line"><span>→ 再次启动</span></span></code></pre></div><p>反向建仓通常需要：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>触碰边界</span></span>
<span class="line"><span>→ 假突破或快速收回</span></span>
<span class="line"><span>→ 再次测试失败</span></span>
<span class="line"><span>→ 反向运行</span></span></code></pre></div><p>第一根突破 K 线往往波动最大、滑点最差，因此回踩确认通常比第一时间追单更有利于控制风险。</p><h2 id="三、图例一-突破后回踩确认的多头建仓" tabindex="-1">三、图例一：突破后回踩确认的多头建仓 <a class="header-anchor" href="#三、图例一-突破后回踩确认的多头建仓" aria-label="Permalink to &quot;三、图例一：突破后回踩确认的多头建仓&quot;">​</a></h2><p><img src="`+s+`" alt="历史复盘图例：收回关键区域后，回踩守住并继续上行"></p><p><em>图 1：收回关键区域后，回踩守住并继续上行。图中价格仅用于历史复盘，不构成当前点位。</em></p><p>图中蓝圈附近不是因为出现一根阳线就立即追多，而是先观察价格从低位收回关键区域；回踩时没有重新跌回弱势区间，随后再次上行并形成更高的高点和更高的低点。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>位置：前期低点和结构支撑区</span></span>
<span class="line"><span>触发：价格收回关键区域</span></span>
<span class="line"><span>确认：回踩不破，重新向上</span></span>
<span class="line"><span>失效：重新跌回收回区域</span></span>
<span class="line"><span>目标：上方下一个结构阻力区</span></span></code></pre></div><p>第一次收回只能定义为“候选机会”；回踩守住并再次启动后，才具有更高质量。</p><h2 id="四、图例二-突破失败后的空头建仓" tabindex="-1">四、图例二：突破失败后的空头建仓 <a class="header-anchor" href="#四、图例二-突破失败后的空头建仓" aria-label="Permalink to &quot;四、图例二：突破失败后的空头建仓&quot;">​</a></h2><p><img src="`+n+`" alt="历史复盘图例：冲高失败、反抽不过并形成下行"></p><p><em>图 2：冲高失败、反抽不过并形成下行。图中价格仅用于历史复盘，不构成当前点位。</em></p><p>图中价格先向上测试高位，随后快速回落。之后价格反抽，但没有重新站回关键区域和 VWAP，最终持续形成更低的高点和更低的低点。</p><p>合理的空头逻辑不是看到长阴线就做空，而是等待突破被证明失败：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>位置：前高和上方阻力区</span></span>
<span class="line"><span>触发：冲高后快速收回</span></span>
<span class="line"><span>确认：反抽无法重新站回关键区域</span></span>
<span class="line"><span>失效：价格重新站回关键区域并回踩守住</span></span>
<span class="line"><span>目标：下方前低或下一个支撑区</span></span></code></pre></div><h2 id="五、失效点必须先于建仓确定" tabindex="-1">五、失效点必须先于建仓确定 <a class="header-anchor" href="#五、失效点必须先于建仓确定" aria-label="Permalink to &quot;五、失效点必须先于建仓确定&quot;">​</a></h2><p>常见失效情况包括：</p><ul><li>多头突破后重新跌回旧区间</li><li>空头跌破后重新站回关键位</li><li>回踩破坏原有结构</li><li>价格在预期时间内没有向目标移动</li><li>VWAP 或关键位置重新被反向收回</li></ul><p>建仓前必须写清：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我为什么进场？</span></span>
<span class="line"><span>哪里证明我错了？</span></span>
<span class="line"><span>第一目标在哪里？</span></span>
<span class="line"><span>如果价格不动，多久退出？</span></span></code></pre></div><p>如果只能说出“我觉得会涨”或“我觉得会跌”，说明交易仍处于预测阶段。</p><h2 id="六、仓位应随证据增加" tabindex="-1">六、仓位应随证据增加 <a class="header-anchor" href="#六、仓位应随证据增加" aria-label="Permalink to &quot;六、仓位应随证据增加&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>只有位置：观察</span></span>
<span class="line"><span>位置 + 触发：试探或继续等待</span></span>
<span class="line"><span>位置 + 触发 + 回踩确认：建立主要仓位</span></span>
<span class="line"><span>确认 + 延续：才考虑增加</span></span></code></pre></div><p>增加仓位必须发生在新的低风险确认点，而不是价格已经大幅远离关键位之后。</p><h2 id="七、指标的证据权重" tabindex="-1">七、指标的证据权重 <a class="header-anchor" href="#七、指标的证据权重" aria-label="Permalink to &quot;七、指标的证据权重&quot;">​</a></h2><p>单一指标都可能失效：节点可能被直接突破，VWAP 可能被反复穿越，一笔大期权成交不一定代表新建仓，放量也可能是情绪释放。</p><p>更合理的观察顺序是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>价格位置与结构</span></span>
<span class="line"><span>→ 突破或拒绝</span></span>
<span class="line"><span>→ 回踩确认</span></span>
<span class="line"><span>→ VWAP 与市场同步</span></span>
<span class="line"><span>→ 成交量和资金流</span></span>
<span class="line"><span>→ 其他辅助指标</span></span></code></pre></div><p>辅助指标只能提高或降低信心，不能替代价格确认。</p><h2 id="八、第一章执行清单" tabindex="-1">八、第一章执行清单 <a class="header-anchor" href="#八、第一章执行清单" aria-label="Permalink to &quot;八、第一章执行清单&quot;">​</a></h2><p>每笔交易前写下：</p><ul><li>位置：</li><li>触发：</li><li>确认：</li><li>失效：</li><li>第一目标：</li><li>预计持仓时间：</li><li>最大风险：</li></ul><p>执行规则：</p><ol><li>不在关键位置之间的中间区域主动开仓。</li><li>不因为第一根大 K 线追单。</li><li>不因为单一指标或单笔大单建仓。</li><li>回踩没有确认时优先等待。</li><li>仓位随着证据增加，而不是随着情绪增加。</li><li>到达结构目标后分批兑现。</li><li>失效后立即退出，不等待市场“证明自己”。</li></ol><h2 id="本章总结" tabindex="-1">本章总结 <a class="header-anchor" href="#本章总结" aria-label="Permalink to &quot;本章总结&quot;">​</a></h2><p>科学建仓的本质是：</p><blockquote><p>在关键位置等待市场表态，在回踩确认后承担有限风险，并在判断失效时退出。</p></blockquote><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>位置明确</span></span>
<span class="line"><span>→ 触发出现</span></span>
<span class="line"><span>→ 回踩确认</span></span>
<span class="line"><span>→ 小风险建仓</span></span>
<span class="line"><span>→ 结构延续再增加</span></span>
<span class="line"><span>→ 到目标分批兑现</span></span>
<span class="line"><span>→ 失效立即退出</span></span></code></pre></div>`,58)])])}const k=p(t,[["render",c]]);export{m as __pageData,k as default};
